const form = document.querySelector('#contact-form');

// We listen for 'submit' on the FORM, not 'click' on the button
form.addEventListener('submit', function(e) {
  // 1. CRITICAL: Stop the browser from reloading the page!
  e.preventDefault();

  // 2. Grab the data
  const email = form.elements.email.value;

  // 3. Send it to our API in the background
  console.log(`Sending ${email} to server...`);
});

